query:
CREATE TABLE IF NOT EXISTS `siteSettings` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `key` varchar(64) NOT NULL UNIQUE,
  `value` text NOT NULL,
  `updatedAt` timestamp DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS `embedCodes` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `type` enum('submit_deal_form', 'contact_calendar') NOT NULL UNIQUE,
  `code` text,
  `updatedAt` timestamp DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS `resourceLinks` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `key` varchar(64) NOT NULL UNIQUE,
  `label` varchar(255) NOT NULL,
  `url` text,
  `displayOrder` int NOT NULL,
  `updatedAt` timestamp DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS `socialLinks` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `platform` enum('facebook', 'instagram', 'linkedin', 'youtube') NOT NULL UNIQUE,
  `url` text,
  `updatedAt` timestamp DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS `quickLinks` (
  `id` int AUTO_INCREMENT PRIMARY KEY,
  `label` varchar(255) NOT NULL,
  `url` text,
  `displayOrder` int NOT NULL,
  `updatedAt` timestamp DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
);

